#include <stdio.h>

void findLeaders(int arr[], int n) {
    int maxFromRight = arr[n-1];
    int leaders[15]; // n ≤ 15
    int cnt = 0;
    leaders[cnt++] = maxFromRight;
    for (int i = n-2; i >= 0; --i) {
        if (arr[i] > maxFromRight) {
            leaders[cnt++] = arr[i];
            maxFromRight = arr[i];
        }
    }
    // print in original order
    for (int i = cnt-1; i >= 0; --i) {
        printf("%d", leaders[i]);
        if (i) printf(" ");
    }
    printf("\n");
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        int arr[15];
        for (int i = 0; i < n; ++i) scanf("%d", &arr[i]);
        findLeaders(arr, n);
    }
    return 0;
}

