#include <bits/stdc++.h>
using namespace std;

vector<int> findLeaders(const vector<int>& a) {
    int n = a.size();
    vector<int> rev;
    int maxFromRight = a.back();
    rev.push_back(maxFromRight);
    for (int i = n-2; i >= 0; --i) {
        if (a[i] > maxFromRight) {
            rev.push_back(a[i]);
            maxFromRight = a[i];
        }
    }
    reverse(rev.begin(), rev.end());
    return rev;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int n; cin>>n;
        vector<int> a(n);
        for (int &x : a) cin>>x;
        vector<int> ans = findLeaders(a);
        for (size_t i = 0; i < ans.size(); ++i) {
            if (i) cout << ' ';
            cout << ans[i];
        }
        cout << '\n';
    }
    return 0;
}

